frappe.ui.form.on('Payment Entry', {
    party: function(frm) {
        if (!frm.doc.party) {
            frm.set_value('student_class', '');
            frm.set_value('student_section', '');
            frm.set_value('student_category', '');
            return;
        }
        frappe.db.get_value('Student',
            {'full_name': frm.doc.party},
            ['student_class', 'section', 'student_category'],
            function(student) {
                if (student) {
                    frm.set_value('student_class', student.student_class || '');
                    frm.set_value('student_section', student.section || '');
                    frm.set_value('student_category', student.student_category || '');
                }
            }
        );
    },
    fees_structure: function(frm) {
        if (!frm.doc.fees_structure) {
            frm.set_value('academic_year', '');
            frm.set_value('academic_term', '');
            return;
        }
        frappe.db.get_value('Fees Structure',
            frm.doc.fees_structure,
            ['year', 'term'],
            function(fs) {
                if (fs) {
                    frm.set_value('academic_year', fs.year || '');
                    frm.set_value('academic_term', fs.term || '');
                }
            }
        );
    }
});

frappe.ui.form.on('Student', {
    refresh: function(frm) {
        if (!frm.is_new()) {
            frm.set_df_property('has_opening_balance', 'read_only', 1);
            frm.set_df_property('opening_balance', 'read_only', 1);
            frm.set_df_property('opening_balance_date', 'read_only', 1);
        }

        // Override all attach image fields to not auto-save
        ['student_image', 'father_photo', 'mother_photo', 'guardian_photo'].forEach(function(fieldname) {
            var field = frm.get_field(fieldname);
            if (field && field.df) {
                field.on_upload_complete = function() {
                    frm.dirty();
                };
            }
        });
    }
});

// Intercept the file upload save
frappe.ui.form.on('Student', {
    student_image: function(frm) { frm.dirty(); },
    father_photo: function(frm) { frm.dirty(); },
    mother_photo: function(frm) { frm.dirty(); },
    guardian_photo: function(frm) { frm.dirty(); }
});

// Block auto save after file upload on Student form
$(document).on('frappe.ui.form.on_upload_complete', function() {
    if (cur_frm && cur_frm.doctype === 'Student' && cur_frm.is_new()) {
        cur_frm.save_disabled = true;
    }
});

frappe.ui.form.on('Sales Invoice', {
    refresh: function(frm) {
        frappe.db.get_single_value('HA POS Settings', 'can_print_invoice').then(function(can_print_invoice) {
            frm.can_print_invoice = can_print_invoice;
            if (can_print_invoice) {
                frm.add_custom_button(__('Print Invoice'), function() {
                    downloadInvoice(frm.doc.name);
                }, __('Actions'));
            }
        });
    },
    on_submit: function(frm) {
        if (frm.doc.docstatus !== 1) return;
        var doDownload = function(can_print) {
            if (can_print) downloadInvoice(frm.doc.name);
        };
        if (frm.can_print_invoice !== undefined) {
            doDownload(frm.can_print_invoice);
        } else {
            frappe.db.get_single_value('HA POS Settings', 'can_print_invoice').then(doDownload);
        }
    }
});

function downloadInvoice(invoiceNumber) {
    var url = frappe.urllib.get_full_url(
        '/api/method/havano_restaurant_pos.api.download_invoice_json?name=' +
        encodeURIComponent(invoiceNumber) + '&receipt_type='
    );
    var a = document.createElement('a');
    a.href = url;
    a.download = invoiceNumber + '.txt';
    a.target = '_blank';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
}

frappe.ui.form.on("Receipting", {
    refresh: function(frm) {
        calculate_totals(frm);
        set_student_query(frm);

        frm.set_query("account", function() {
            return {
                filters: {
                    "account_type": ["in", ["Cash", "Bank"]],
                    "is_group": 0
                }
            };
        });

        if (frm.doc.docstatus === 0 && !frm.is_new()) {
            frm.add_custom_button("Submit", function() {
                frappe.confirm("Are you sure you want to submit this receipt?", function() {
                    frappe.call({
                        method: "frappe.client.submit",
                        args: { doc: frm.doc },
                        callback: function(r) {
                            if (r.message) {
                                frappe.model.sync(r.message);
                                frm.reload_doc();
                                frappe.msgprint("Receipting submitted successfully.");
                            }
                        }
                    });
                });
            }, "primary");
        }
    },

    student_name: function(frm) {
        if (!frm.doc.student_name) {
            frm.clear_table("invoice");
            frm.refresh_field("invoice");
            frm.set_value("total_amount", 0);
            frm.set_value("total_outstanding", 0);
            frm.set_value("total_balance", 0);
            return;
        }
        frappe.db.get_value("Student", frm.doc.student_name,
            ["full_name", "student_class", "section"],
            function(r) {
                if (r) {
                    if (r.student_class) frm.set_value("student_class", r.student_class);
                    if (r.section) frm.set_value("section", r.section);
                }
            }
        );
        load_student_invoices(frm);
    },

    student_class: function(frm) { set_student_query(frm); },
    section: function(frm) { set_student_query(frm); }
});

frappe.ui.form.on("Receipt Item", {
    allocated: function(frm, cdt, cdn) { calculate_totals(frm); },
    invoices_remove: function(frm) { calculate_totals(frm); }
});

function set_student_query(frm) {
    frm.set_query("student_name", function() {
        let filters = {};
        if (frm.doc.student_class) filters.student_class = frm.doc.student_class;
        if (frm.doc.section) filters.section = frm.doc.section;
        return { filters: filters };
    });
}

function load_student_invoices(frm) {
    if (!frm.doc.student_name) return;
    frappe.show_alert({message: "Loading invoices...", indicator: "blue"});
    frappe.call({
        method: "school.api.get_student_invoices",
        args: { student: frm.doc.student_name },
        callback: function(res) {
            if (res.message && res.message.length) {
                let rows = res.message.map(function(inv) {
                    return {
                        doctype: "Receipt Item",
                        invoice_number: inv.name,
                        fees_structure: inv.fees_structure || "",
                        total: inv.grand_total,
                        outstanding: inv.outstanding_amount,
                        allocated: 0
                    };
                });
                frm.set_value("invoice", rows);
                setTimeout(function() {
                    frm.refresh_field("invoice");
                    calculate_totals(frm);
                }, 300);
                frappe.show_alert({message: res.message.length + " invoice(s) loaded", indicator: "green"});
            } else {
                frm.clear_table("invoice");
                frm.refresh_field("invoice");
                frm.set_value("total_amount", 0);
                frm.set_value("total_outstanding", 0);
                frm.set_value("total_balance", 0);
                frappe.show_alert({message: "No outstanding invoices found", indicator: "orange"});
            }
        }
    });
}

function calculate_totals(frm) {
    let total_outstanding = 0, total_allocated = 0;
    (frm.doc.invoice || []).forEach(function(row) {
        total_outstanding += row.outstanding || 0;
        total_allocated += row.allocated || 0;
    });
    frm.set_value("total_outstanding", total_outstanding);
    frm.set_value("total_amount", total_allocated);
    frm.set_value("total_balance", total_outstanding - total_allocated);
}

frappe.ui.form.on('Test Schedule', {
    test_name: function(frm) {
        if (frm.doc.test_name) {
            frappe.db.get_value('Inclass Test', frm.doc.test_name, ['max_marks_percent', 'min_marks_percent'], function(r) {
                if (r) {
                    frm.set_value('max_marks', r.max_marks_percent);
                    frm.set_value('min_marks', r.min_marks_percent);
                }
            });
        }
    },
    student_class: function(frm) {
        frm.clear_table('test_items');
        frm.refresh_field('test_items');
    },

    section: function(frm) {
        frm.clear_table('test_items');
        frm.refresh_field('test_items');
    },

    fetch_students: function(frm) {
        if (!frm.doc.student_class) {
            frappe.msgprint(__('Please select a Class first'));
            return;
        }

        let filters = {'student_class': frm.doc.student_class};
        if (frm.doc.section) {
            filters['section'] = frm.doc.section;
        }

        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Student',
                filters: filters,
                fields: ['name', 'student_reg_no', 'full_name'],
                limit_page_length: 0,
                order_by: 'student_reg_no'
            },
            callback: function(r) {
                if (r.message && r.message.length > 0) {
                    frm.clear_table('test_items');
                    r.message.forEach(function(student) {
                        let row = frm.add_child('test_items');
                        row.student = student.name;
                        row.student_reg_no = student.student_reg_no;
                        row.student_name = student.full_name;
                    });
                    frm.refresh_field('test_items');
                    frappe.show_alert({
                        message: __('{0} students added', [r.message.length]),
                        indicator: 'green'
                    });
                } else {
                    frappe.msgprint(__('No students found'));
                }
            }
        });
    }
});

